definition.customCSS:
#banner, #footer {
  display: none;
}

#p_p_id_com_liferay_login_web_portlet_LoginPortlet_ {
  background: #FFF;
  left: 50%;
  padding: 1.5rem;
  position: fixed;
  top: 50%;
  transform: translate(-50%, -50%);
  width: 25rem;
}

#p_p_id_com_liferay_login_web_portlet_LoginPortlet_ .button-holder .btn {
  width: 100%;
}

#p_p_id_com_liferay_login_web_portlet_LoginPortlet_ .navigation li {
  float: none;
  margin: 0;
  padding: 0.25rem 0;
}

#p_p_id_com_liferay_login_web_portlet_LoginPortlet_ .navigation li a {
  color: var(--gray-800);
  font-size: 0.9rem;
}

#p_p_id_com_liferay_login_web_portlet_LoginPortlet_ .panel-body {
  padding: 0.75rem 0;
}

#p_p_id_com_liferay_login_web_portlet_LoginPortlet_ .portlet .portlet-title-text {
  color: var(--black, #000);
  font-size: 1.125rem;
  margin-bottom: 1rem;
}
